protected void new(PackingSlipId _grnNumber, ItemId _itemId, Qty _quantity, AmountCur _amount, CurrencyCode _currency)
{
    grnNumber   = _grnNumber;
    itemId      = _itemId;
    quantity    = _quantity;
    amount      = _amount;
    currency    = _currency;
}

public static PurchGRNLineBusinessEventContract construct(PackingSlipId _grnNumber, ItemId _itemId, Qty _quantity, AmountCur _amount, CurrencyCode _currency)
{
    return new PurchGRNLineBusinessEventContract(_grnNumber, _itemId, _quantity, _amount, _currency);
}

[DataMember('GRN Number'), BusinessEventsDataMember('GRN Number')]
public PackingSlipId parmGRNNumber(PackingSlipId _grnNumber = grnNumber)
{
    grnNumber = _grnNumber;
    return grnNumber;
}

[DataMember('Item Id'), BusinessEventsDataMember('Item Id')]
public ItemId parmItemId(ItemId _itemId = itemId)
{
    itemId = _itemId;
    return itemId;
}

[DataMember('Quantity'), BusinessEventsDataMember('Quantity')]
public Qty parmQuantity(Qty _quantity = quantity)
{
    quantity = _quantity;
    return quantity;
}

[DataMember('Amount'), BusinessEventsDataMember('Amount')]
public AmountCur parmAmount(AmountCur _amount = amount)
{
